#nullable enable // autogenerated

using MVZ2.Vanilla.Entities;
using MVZ2.Vanilla.Properties;
using MVZ2Logic.Level;
using PVZEngine.Definitions;
using PVZEngine.Entities;
using PVZEngine.Modifiers;
using UnityEngine;

namespace MVZ2.GameContent.Effects
{
    [AutoEntityBehaviourDefinition(VanillaEffectNames.floatingText)]
    public class FloatingText : EffectBehaviour
    {
        public FloatingText(string nsp, string name) : base(nsp, name)
        {
            AddModifier(new Vector3Modifier(EngineEntityProps.MODEL_POSITION_OFFSET, NumberOperator.Add, PROP_MODEL_OFFSET));
        }
        public override void Update(Entity entity)
        {
            base.Update(entity);
            entity.SetModelProperty("Color", entity.GetTint());
            entity.SetModelProperty("Text", GetText(entity));
            var zOffset = Mathf.Lerp(10, 0, entity.Timeout / (float)entity.GetMaxTimeout());
            entity.SetModelPositionOffset(Vector3.forward * zOffset);
        }
        public static string? GetText(Entity entity) => entity.GetBehaviourField<string>(PROP_TEXT);
        public static void SetText(Entity entity, string value) => entity.SetBehaviourField(PROP_TEXT, value);
        public static Vector3 GetModelOffset(Entity entity) => entity.GetBehaviourField<Vector3>(PROP_MODEL_OFFSET);
        public static void SetModelOffset(Entity entity, Vector3 value) => entity.SetBehaviourField(PROP_MODEL_OFFSET, value);

        public static readonly VanillaEntityPropertyMeta<string> PROP_TEXT = new VanillaEntityPropertyMeta<string>("Text");
        public static readonly VanillaEntityPropertyMeta<Vector3> PROP_MODEL_OFFSET = new VanillaEntityPropertyMeta<Vector3>("model_offset");
    }
}